// ═══════════════════════════════════════════════════════════════════════
// СХЕМА ОТКРЫВАНИЯ ДВЕРИ — Invisible Doors
// 4 картинки фото + 4 технические схемы (без динамики цвета)
// Используется в калькуляторе (справа от чека) и в КП (index.html).
// ═══════════════════════════════════════════════════════════════════════

window.DOOR_IMG = {
  l1_photo: 'data:image/jpeg;base64,',
  l2_photo: 'data:image/jpeg;base64,',
  r1_photo: 'data:image/jpeg;base64,',
  r2_photo: 'data:image/jpeg;base64,',
  l1_scheme: 'data:image/jpeg;base64,',
  l2_scheme: 'data:image/jpeg;base64,',
  r1_scheme: 'data:image/jpeg;base64,',
  r2_scheme: 'data:image/jpeg;base64,',
};

// Главная функция: возвращает HTML-блок с фото + схемой
// opening: 'internal' | 'external' | 'lift' | 'none'
// side:    'left' | 'right' | 'doble' | 'none'
// width:   ширина блока в px (по умолчанию 220)
window.renderDoorDiagram = function(opening, side, width) {
  width = width || 220;
  var titles = {
    'external_left':  'Внешнее левое',
    'internal_left':  'Внутреннее левое',
    'external_right': 'Внешнее правое',
    'internal_right': 'Внутреннее правое',
    'lift_left':      'Откатная (лево)',
    'lift_right':     'Откатная (право)'
  };
  var key = opening + '_' + side;
  var title = titles[key] || '';

  if (!opening || opening === 'none' || !side || side === 'none') {
    return '<div style="width:' + width + 'px;padding:20px;text-align:center;color:#888;font-size:11px;border:1px dashed #ccc;border-radius:6px;background:#fafafa">🚪 Выберите открывание<br>и сторону</div>';
  }
  if (side === 'doble') {
    // Двустворчатая - показываем 2 картинки (лево + право) рядом
    var leftHtml = window.renderDoorDiagram(opening, 'left', Math.floor(width / 2) - 6);
    var rightHtml = window.renderDoorDiagram(opening, 'right', Math.floor(width / 2) - 6);
    return '<div style="display:flex;gap:8px">' + leftHtml + rightHtml + '</div>';
  }

  if (opening === 'lift') opening = 'external';
  var imgKey = (side === 'left' ? 'l' : 'r') + (opening === 'external' ? '1' : '2');
  var photo = window.DOOR_IMG[imgKey + '_photo'];
  var scheme = window.DOOR_IMG[imgKey + '_scheme'];
  if (!photo || !scheme) {
    return '<div style="color:#c00;font-size:11px">⚠ Картинка не найдена для ' + key + '</div>';
  }

  return (
    '<div class="door-diagram" data-key="' + key + '"' + 
         ' style="width:' + width + 'px;background:#fff;border:1px solid #e5e5e5;border-radius:8px;overflow:hidden;font-family:-apple-system,Arial,sans-serif">' +
      '<div style="text-align:center;padding:8px 4px 4px;font-size:13px;font-weight:600;color:#444">' + title + '</div>' +
      '<img src="' + photo + '" style="width:100%;display:block" alt="' + title + '"/>' +
      '<div style="background:#fff;padding:8px 6px 6px;text-align:center">' +
        '<img src="' + scheme + '" style="width:80%;max-width:170px;display:block;margin:0 auto" alt="схема"/>' +
      '</div>' +
    '</div>'
  );
};
